#include <iostream>
#include <string>
#include <iomanip>
#include <vector>
#include <tuple>

class Date {
private:
    int day;
    int month;
    int year;

    bool isLeap(int y) const {
        return (y % 4 == 0 && y % 100 != 0) || (y % 400 == 0);
    }

public:
    Date(int d, int m, int y) : day(d), month(m), year(y) {}

    bool isValidDate() const {
        if (year <= 0) return false;
        if (month < 1 || month > 12) return false;
        if (day < 1) return false;

        int daysInMonth[] = {0, 31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31};
        if (isLeap(year)) {
            daysInMonth[2] = 29;
        }

        return day <= daysInMonth[month];
    }

    void displayDate() const {
        std::cout << std::setfill('0') << std::setw(2) << day << '/'
                  << std::setfill('0') << std::setw(2) << month << '/'
                  << std::setfill('0') << std::setw(4) << year;
    }
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::vector<std::tuple<int, int, int>> inputs = {
        {15, 3, 2023},
        {29, 2, 2024},
        {29, 2, 2023},
        {31, 4, 2023},
        {31, 1, 2023},
        {1, 13, 2023},
        {1, 0, 2023},
        {0, 1, 2023},
        {29, 2, 2000},
        {29, 2, 1900},
        {1, 1, 0},
        {1, 1, -2023}
    };

    for (const auto& input_tuple : inputs) {
        int d = std::get<0>(input_tuple);
        int m = std::get<1>(input_tuple);
        int y = std::get<2>(input_tuple);

        Date date(d, m, y);
        std::cout << "Input: " << d << " " << m << " " << y << "\n";
        std::cout << "isValid: " << (date.isValidDate() ? "true" : "false") << ", display: ";
        date.displayDate();
        std::cout << "\n";
    }
    return 0;
}
